-- Migration 006: Catalogo de mercados pre-poblado desde Excel
-- 259 mercados con estatus CATALOGO_LIMPIO

-- 1) Crear tabla catalogo_mercados
CREATE TABLE IF NOT EXISTS catalogo_mercados (
    id SERIAL PRIMARY KEY,
    market_id VARCHAR(30) UNIQUE NOT NULL,
    nombre VARCHAR(200) NOT NULL,
    tipo VARCHAR(50) NOT NULL,
    entidad VARCHAR(100) NOT NULL,
    municipio VARCHAR(100) NOT NULL,
    localidad VARCHAR(150),
    latitud DOUBLE PRECISION,
    longitud DOUBLE PRECISION,
    n_establecimientos INTEGER DEFAULT 0,
    cve_ent VARCHAR(5),
    cve_mun VARCHAR(5)
);

-- 2) Modificar tabla mercados: agregar referencia al catalogo
ALTER TABLE mercados ADD COLUMN IF NOT EXISTS catalogo_mercado_id INTEGER REFERENCES catalogo_mercados(id);
ALTER TABLE mercados ADD COLUMN IF NOT EXISTS latitud DOUBLE PRECISION;
ALTER TABLE mercados ADD COLUMN IF NOT EXISTS longitud DOUBLE PRECISION;

-- 3) Insertar los 259 mercados del catalogo

-- 4) Crear indices para busqueda rapida
CREATE INDEX IF NOT EXISTS idx_cat_mercados_entidad ON catalogo_mercados(entidad);
CREATE INDEX IF NOT EXISTS idx_cat_mercados_municipio ON catalogo_mercados(municipio);
CREATE INDEX IF NOT EXISTS idx_cat_mercados_nombre ON catalogo_mercados(nombre);
CREATE INDEX IF NOT EXISTS idx_cat_mercados_tipo ON catalogo_mercados(tipo);